const staticData = getWorkflowStaticData('global');
if (!staticData.users) { staticData.users = []; }

const body = items[0].json.body;

// Check if user already exists
const existingUser = staticData.users.find(u => u.cedula === body.cedula);
if (existingUser) {
  return [{ json: { success: false, message: 'Usuario ya registrado con esta cédula' } }];
}

// Create new user with phone field
const newUser = {
  id: Date.now(),
  name: body.name,
  email: body.email,
  cedula: body.cedula,
  phone: body.phone || '',
  role: body.role,
  type: body.type || '',
  notes: [],
  createdAt: new Date().toISOString()
};

staticData.users.push(newUser);

return [{ json: { success: true, user: newUser, message: 'Usuario registrado exitosamente' } }];

const staticData = getWorkflowStaticData('global');
if (!staticData.users) { staticData.users = []; }

const query = items[0].json.query || {};

// Filter by cedula if provided
if (query.cedula) {
  const user = staticData.users.find(u => u.cedula === query.cedula);
  if (user) {
    return [{ json: { success: true, user: user } }];
  } else {
    return [{ json: { success: false, message: 'Usuario no encontrado' } }];
  }
}

// Filter by role if provided
if (query.role) {
  const filteredUsers = staticData.users.filter(u => u.role === query.role);
  return [{ json: { success: true, users: filteredUsers, count: filteredUsers.length } }];
}

// Return all users
return [{ json: { success: true, users: staticData.users, count: staticData.users.length } }];

const staticData = getWorkflowStaticData('global');
if (!staticData.users) { staticData.users = []; }

const body = items[0].json.body;

if (!body.cedula) {
  return [{ json: { success: false, message: 'Cédula requerida' } }];
}

const userIndex = staticData.users.findIndex(u => u.cedula === body.cedula);

if (userIndex === -1) {
  return [{ json: { success: false, message: 'Usuario no encontrado' } }];
}

// Update user fields (including phone)
if (body.name) staticData.users[userIndex].name = body.name;
if (body.email) staticData.users[userIndex].email = body.email;
if (body.phone !== undefined) staticData.users[userIndex].phone = body.phone;
if (body.notes) staticData.users[userIndex].notes = body.notes;

staticData.users[userIndex].updatedAt = new Date().toISOString();

return [{ json: { success: true, user: staticData.users[userIndex], message: 'Usuario actualizado' } }];

const staticData = getWorkflowStaticData('global');
if (!staticData.users) { staticData.users = []; }

const body = items[0].json.body;

if (!body.cedula) {
  return [{ json: { success: false, message: 'Cédula requerida' } }];
}

const userIndex = staticData.users.findIndex(u => u.cedula === body.cedula);

if (userIndex === -1) {
  return [{ json: { success: false, message: 'Usuario no encontrado' } }];
}

const deletedUser = staticData.users.splice(userIndex, 1)[0];

return [{ json: { success: true, user: deletedUser, message: 'Usuario eliminado exitosamente' } }];
